return-response.set-body:
@{
                var mcpPath = context.Request.MatchedParameters["mcpPath"];
                var gatewayUrl = "{{APIMGatewayURL}}";
                return JsonConvert.SerializeObject(new {
                    resource = $"{gatewayUrl}/{mcpPath}",
                    authorization_servers = new[] {
                        $"https://login.microsoftonline.com/{{entraid-tenant}}/v2.0"
                    },
                    bearer_methods_supported = new[] {
                        "header"
                    },
                    scopes_supported = new[] {
                        "api://{{obo-client-id}}/access_mcp"
                    }
                });
            }
